"use strict";(globalThis.webpackChunkantifraud_docs=globalThis.webpackChunkantifraud_docs||[]).push([[875],{7519(n,e,t){t.r(e),t.d(e,{assets:()=>p,contentTitle:()=>o,default:()=>u,frontMatter:()=>r,metadata:()=>s,toc:()=>m});const s=JSON.parse('{"id":"API/specs","title":"\u0421\u043f\u0435\u0446\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f API","description":"\u0421\u043f\u0435\u0446\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f (OpenAPI)","source":"@site/docs/API/specs.md","sourceDirName":"API","slug":"/API/specs","permalink":"/t-academy_documentation_task/docs/API/specs","draft":false,"unlisted":false,"editUrl":"https://github.com/yauhenkaaa/t-academy_documentation_task/edit/main/antifraud-docs/docs/API/specs.md","tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"title":"\u0421\u043f\u0435\u0446\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f API","sidebar_position":1,"hide_table_of_contents":false},"sidebar":"tutorialSidebar","previous":{"title":"API","permalink":"/t-academy_documentation_task/docs/category/api"},"next":{"title":"\u041e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u044f \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u044f \u0434\u0430\u043d\u043d\u044b\u0445","permalink":"/t-academy_documentation_task/docs/category/\u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u044f-\u0445\u0440\u0430\u043d\u0435\u043d\u0438\u044f-\u0434\u0430\u043d\u043d\u044b\u0445"}}');var a=t(4848),i=t(8453);const r={title:"\u0421\u043f\u0435\u0446\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f API",sidebar_position:1,hide_table_of_contents:!1},o=void 0,p={},m=[{value:"\u0421\u043f\u0435\u0446\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f (OpenAPI)",id:"\u0441\u043f\u0435\u0446\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f-openapi",level:2}];function c(n){const e={code:"code",h2:"h2",pre:"pre",...(0,i.R)(),...n.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(e.h2,{id:"\u0441\u043f\u0435\u0446\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f-openapi",children:"\u0421\u043f\u0435\u0446\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f (OpenAPI)"}),"\n",(0,a.jsx)(e.pre,{children:(0,a.jsx)(e.code,{className:"language-yaml",children:"openapi: 3.0.3\ninfo:\n  title: Call Analysis System API\n  description: >\n    \u0421\u043f\u0435\u0446\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u043e\u0432 \u0434\u0430\u043d\u043d\u044b\u0445 \u0434\u043b\u044f \u0440\u0435\u0430\u043b\u0438\u0437\u0430\u0446\u0438\u0438 \u044d\u043a\u0440\u0430\u043d\u043e\u0432 /main \u0438 /whitelist.\n  version: 1.0.0\n  contact:\n    name: \u041a\u0443\u0440\u0441\u043e\u0432\u043e\u0439 \u043f\u0440\u043e\u0435\u043a\u0442\n\nservers:\n  - url: https://api.callsys.local/v1\n\npaths:\n  /users/me:\n    get:\n      tags: [Header]\n      summary: \u041f\u043e\u043b\u0443\u0447\u0438\u0442\u044c \u043f\u0440\u043e\u0444\u0438\u043b\u044c \u0442\u0435\u043a\u0443\u0449\u0435\u0433\u043e \u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u044f\n      operationId: getCurrentUser\n      responses:\n        '200':\n          description: \u0423\u0441\u043f\u0435\u0448\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/User'\n\n  /notifications/unread:\n    get:\n      tags: [Header]\n      summary: \u041f\u043e\u043b\u0443\u0447\u0438\u0442\u044c \u0441\u0447\u0451\u0442\u0447\u0438\u043a \u0438 \u0441\u043f\u0438\u0441\u043e\u043a \u043d\u0435\u043f\u0440\u043e\u0447\u0438\u0442\u0430\u043d\u043d\u044b\u0445 \u0443\u0432\u0435\u0434\u043e\u043c\u043b\u0435\u043d\u0438\u0439\n      operationId: getUnreadNotifications\n      responses:\n        '200':\n          description: \u0423\u0441\u043f\u0435\u0448\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/NotificationSummary'\n\n  /calls:\n    get:\n      tags: [Calls]\n      summary: \u041f\u043e\u043b\u0443\u0447\u0438\u0442\u044c \u043b\u0435\u043d\u0442\u0443 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0445 \u0432\u044b\u0437\u043e\u0432\u043e\u0432\n      operationId: listCalls\n      parameters:\n        - name: limit\n          in: query\n          required: false\n          schema: { type: integer, minimum: 5, maximum: 50, default: 10 }\n          description: \u041a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e \u0437\u0430\u043f\u0438\u0441\u0435\u0439 \u043d\u0430 \u0441\u0442\u0440\u0430\u043d\u0438\u0446\u0435\n        - name: sort\n          in: query\n          required: false\n          schema: { type: string, enum: [timestamp_desc, threat_desc], default: threat_desc }\n          description: \u041a\u0440\u0438\u0442\u0435\u0440\u0438\u0439 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0438 \u0441\u043f\u0438\u0441\u043a\u0430\n      responses:\n        '200':\n          description: \u041f\u0430\u0433\u0438\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0441\u043f\u0438\u0441\u043e\u043a \u0432\u044b\u0437\u043e\u0432\u043e\u0432\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/PaginatedCallResponse'\n\n  /calls/{id}/audio:\n    get:\n      tags: [Calls]\n      summary: \u041f\u043e\u043b\u0443\u0447\u0438\u0442\u044c \u0430\u0443\u0434\u0438\u043e\u0444\u0430\u0439\u043b \u0438\u043b\u0438 URL \u043f\u043e\u0442\u043e\u043a\u0430 \u0432\u044b\u0437\u043e\u0432\u0430\n      operationId: getCallAudio\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema: { type: string, format: uuid }\n          description: \u0423\u043d\u0438\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u0438\u0434\u0435\u043d\u0442\u0438\u0444\u0438\u043a\u0430\u0442\u043e\u0440 \u0432\u044b\u0437\u043e\u0432\u0430\n      responses:\n        '200':\n          description: URL \u0430\u0443\u0434\u0438\u043e \u0438\u043b\u0438 \u0431\u0438\u043d\u0430\u0440\u043d\u044b\u0439 \u043f\u043e\u0442\u043e\u043a\n          content:\n            application/json:\n              schema:\n                type: object\n                properties:\n                  audioUrl: { type: string, format: uri }\n                  duration: { type: integer, minimum: 0 }\n\n  /calls/{id}/status:\n    post:\n      tags: [Calls]\n      summary: \u0418\u0437\u043c\u0435\u043d\u0438\u0442\u044c \u0441\u0442\u0430\u0442\u0443\u0441 \u0432\u044b\u0437\u043e\u0432\u0430 (\u0431\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u043a\u0430/\u0440\u0430\u0437\u0440\u0435\u0448\u0435\u043d\u0438\u0435)\n      operationId: updateCallStatus\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema: { type: string, format: uuid }\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/UpdateCallStatusRequest'\n      responses:\n        '200':\n          description: \u0421\u0442\u0430\u0442\u0443\u0441 \u043e\u0431\u043d\u043e\u0432\u043b\u0451\u043d\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/Call'\n\n  /numbers/{id}/tag:\n    post:\n      tags: [Calls]\n      summary: \u041c\u0430\u0440\u043a\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043d\u043e\u043c\u0435\u0440 \u0432\u044b\u0437\u043e\u0432\u0430\n      operationId: tagCallNumber\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema: { type: string, format: uuid }\n          description: \u0418\u0434\u0435\u043d\u0442\u0438\u0444\u0438\u043a\u0430\u0442\u043e\u0440 \u0432\u044b\u0437\u043e\u0432\u0430/\u043d\u043e\u043c\u0435\u0440\u0430\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/TagNumberRequest'\n      responses:\n        '200':\n          description: \u041c\u0430\u0440\u043a\u0438\u0440\u043e\u0432\u043a\u0430 \u043f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0430\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/Call'\n  /whitelist:\n    get:\n      tags: [Whitelist]\n      summary: \u041f\u043e\u043b\u0443\u0447\u0438\u0442\u044c \u0441\u043f\u0438\u0441\u043e\u043a \u0437\u0430\u043f\u0438\u0441\u0435\u0439 \u0431\u0435\u043b\u043e\u0433\u043e \u0441\u043f\u0438\u0441\u043a\u0430 \u0441 \u0444\u0438\u043b\u044c\u0442\u0440\u0430\u0446\u0438\u0435\u0439\n      operationId: getWhitelist\n      parameters:\n        - name: page\n          in: query\n          required: false\n          schema: { type: integer, minimum: 1, default: 1 }\n          description: \u041d\u043e\u043c\u0435\u0440 \u0441\u0442\u0440\u0430\u043d\u0438\u0446\u044b\n        - name: limit\n          in: query\n          required: false\n          schema: { type: integer, minimum: 10, maximum: 100, default: 20 }\n          description: \u0417\u0430\u043f\u0438\u0441\u0435\u0439 \u043d\u0430 \u0441\u0442\u0440\u0430\u043d\u0438\u0446\u0443\n        - name: search\n          in: query\n          required: false\n          schema: { type: string, minLength: 1, maxLength: 30 }\n          description: \u0424\u0438\u043b\u044c\u0442\u0440 \u043f\u043e \u043d\u043e\u043c\u0435\u0440\u0443 \u0442\u0435\u043b\u0435\u0444\u043e\u043d\u0430 \u0438\u043b\u0438 \u043a\u043e\u043c\u043c\u0435\u043d\u0442\u0430\u0440\u0438\u044e\n      responses:\n        '200':\n          description: \u041f\u0430\u0433\u0438\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0441\u043f\u0438\u0441\u043e\u043a \u0437\u0430\u043f\u0438\u0441\u0435\u0439\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/PaginatedWhitelistResponse'\n\n    post:\n      tags: [Whitelist]\n      summary: \u0414\u043e\u0431\u0430\u0432\u0438\u0442\u044c \u043d\u043e\u043c\u0435\u0440 \u0432 \u0431\u0435\u043b\u044b\u0439 \u0441\u043f\u0438\u0441\u043e\u043a\n      operationId: createWhitelistEntry\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/CreateWhitelistRequest'\n      responses:\n        '201':\n          description: \u0417\u0430\u043f\u0438\u0441\u044c \u0443\u0441\u043f\u0435\u0448\u043d\u043e \u0441\u043e\u0437\u0434\u0430\u043d\u0430\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/WhitelistEntry'\n\n  /whitelist/{id}:\n    put:\n      tags: [Whitelist]\n      summary: \u041e\u0431\u043d\u043e\u0432\u0438\u0442\u044c \u0437\u0430\u043f\u0438\u0441\u044c \u0431\u0435\u043b\u043e\u0433\u043e \u0441\u043f\u0438\u0441\u043a\u0430\n      operationId: updateWhitelistEntry\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema: { type: string, format: uuid }\n      requestBody:\n        required: true\n        content:\n          application/json:\n            schema:\n              $ref: '#/components/schemas/UpdateWhitelistRequest'\n      responses:\n        '200':\n          description: \u041e\u0431\u043d\u043e\u0432\u043b\u0451\u043d\u043d\u0430\u044f \u0437\u0430\u043f\u0438\u0441\u044c\n          content:\n            application/json:\n              schema:\n                $ref: '#/components/schemas/WhitelistEntry'\n\n    delete:\n      tags: [Whitelist]\n      summary: \u0423\u0434\u0430\u043b\u0438\u0442\u044c \u0437\u0430\u043f\u0438\u0441\u044c \u0438\u0437 \u0431\u0435\u043b\u043e\u0433\u043e \u0441\u043f\u0438\u0441\u043a\u0430\n      operationId: deleteWhitelistEntry\n      parameters:\n        - name: id\n          in: path\n          required: true\n          schema: { type: string, format: uuid }\n      responses:\n        '204':\n          description: \u0423\u0441\u043f\u0435\u0448\u043d\u043e \u0443\u0434\u0430\u043b\u0435\u043d\u043e\n\ncomponents:\n  schemas:\n    CallStatus:\n      type: string\n      enum: [PENDING, ANALYZING, ALLOWED, BLOCKED, SUSPICIOUS]\n      description: \u0421\u0442\u0430\u0442\u0443\u0441 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0432\u044b\u0437\u043e\u0432\u0430\n\n    CallDirection:\n      type: string\n      enum: [INCOMING, OUTGOING, MISSED]\n      description: \u041d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0432\u044b\u0437\u043e\u0432\u0430\n\n    TagCategory:\n      type: string\n      enum: [SPAM, FRAUD, SERVICE, SAFE, OTHER]\n      description: \u041a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u044f \u043c\u0430\u0440\u043a\u0438\u0440\u043e\u0432\u043a\u0438 \u043d\u043e\u043c\u0435\u0440\u0430\n\n    UserRole:\n      type: string\n      enum: [USER, GROUP_MEMBER, ADMIN]\n      description: \u0420\u043e\u043b\u044c \u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u044f\n\n    ActionType:\n      type: string\n      enum: [PLAY_AUDIO, BLOCK, ALLOW, MARK, ADD_TO_WHITELIST]\n      description: \u0414\u043e\u0441\u0442\u0443\u043f\u043d\u043e\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0434\u043b\u044f \u0432\u044b\u0437\u043e\u0432\u0430\n\n    AnalysisResult:\n      type: object\n      required: [threatLevel, confidence, systemTags]\n      properties:\n        threatLevel:\n          type: string\n          enum: [LOW, MEDIUM, HIGH, CRITICAL]\n        confidence:\n          type: number\n          format: float\n          minimum: 0.0\n          maximum: 1.0\n        systemTags:\n          type: array\n          items: { type: string }\n          description: \u0410\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043c\u0435\u0442\u043a\u0438 \u043e\u0442 \u0441\u0438\u0441\u0442\u0435\u043c\u044b \u0430\u043d\u0430\u043b\u0438\u0437\u0430\n\n    AddedByInfo:\n      type: object\n      required: [userId, username, role]\n      properties:\n        userId: { type: string, format: uuid }\n        username: { type: string }\n        role: { $ref: '#/components/schemas/UserRole' }\n\n    PaginationMeta:\n      type: object\n      required: [page, limit, total, hasNext]\n      properties:\n        page: { type: integer }\n        limit: { type: integer }\n        total: { type: integer }\n        hasNext: { type: boolean }\n\n    User:\n      type: object\n      required: [id, username, role]\n      properties:\n        id: { type: string, format: uuid }\n        username: { type: string }\n        role: { $ref: '#/components/schemas/UserRole' }\n        avatarUrl: { type: string, format: uri, nullable: true }\n\n    Notification:\n      type: object\n      required: [id, message, type, createdAt]\n      properties:\n        id: { type: string, format: uuid }\n        message: { type: string }\n        type: { type: string, enum: [INFO, WARNING, ALERT] }\n        createdAt: { type: string, format: date-time }\n\n    NotificationSummary:\n      type: object\n      required: [unreadCount, items]\n      properties:\n        unreadCount: { type: integer, minimum: 0 }\n        items:\n          type: array\n          items: { $ref: '#/components/schemas/Notification' }\n\n    Call:\n      type: object\n      required: [id, phoneNumber, timestamp, status, direction, analysisResult]\n      properties:\n        id: { type: string, format: uuid }\n        phoneNumber: { type: string, pattern: '^\\+\\d{10,15}$' }\n        timestamp: { type: string, format: date-time }\n        status: { $ref: '#/components/schemas/CallStatus' }\n        direction: { $ref: '#/components/schemas/CallDirection' }\n        analysisResult: { $ref: '#/components/schemas/AnalysisResult' }\n        availableActions:\n          type: array\n          items: { $ref: '#/components/schemas/ActionType' }\n        audioUrl: { type: string, format: uri, nullable: true }\n\n    WhitelistEntry:\n      type: object\n      required: [id, phoneNumber, createdAt, addedBy]\n      properties:\n        id: { type: string, format: uuid }\n        phoneNumber: { type: string, pattern: '^\\+\\d{10,15}$' }\n        comment: { type: string, maxLength: 255, nullable: true }\n        applyToGroup: { type: boolean, default: false }\n        createdAt: { type: string, format: date-time }\n        addedBy: { $ref: '#/components/schemas/AddedByInfo' }\n        userTags:\n          type: array\n          items: { type: string }\n          description: \u041f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u0441\u043a\u0438\u0435 \u043c\u0435\u0442\u043a\u0438 \u0437\u0430\u043f\u0438\u0441\u0438\n\n    UpdateCallStatusRequest:\n      type: object\n      required: [action]\n      properties:\n        action:\n          type: string\n          enum: [BLOCK, ALLOW, UNBLOCK]\n        reason: { type: string, maxLength: 100, nullable: true }\n\n    TagNumberRequest:\n      type: object\n      required: [tag]\n      properties:\n        tag:\n          $ref: '#/components/schemas/TagCategory'\n\n    CreateWhitelistRequest:\n      type: object\n      required: [phoneNumber]\n      properties:\n        phoneNumber: { type: string, pattern: '^\\+\\d{10,15}$' }\n        comment: { type: string, maxLength: 255 }\n        applyToGroup: { type: boolean, default: false }\n\n    UpdateWhitelistRequest:\n      type: object\n      properties:\n        comment: { type: string, maxLength: 255 }\n        applyToGroup: { type: boolean }\n        userTags:\n          type: array\n          items: { type: string }\n\n    PaginatedCallResponse:\n      type: object\n      properties:\n        data:\n          type: array\n          items: { $ref: '#/components/schemas/Call' }\n        meta: { $ref: '#/components/schemas/PaginationMeta' }\n\n    PaginatedWhitelistResponse:\n      type: object\n      properties:\n        data:\n          type: array\n          items: { $ref: '#/components/schemas/WhitelistEntry' }\n        meta: { $ref: '#/components/schemas/PaginationMeta' }\n"})})]})}function u(n={}){const{wrapper:e}={...(0,i.R)(),...n.components};return e?(0,a.jsx)(e,{...n,children:(0,a.jsx)(c,{...n})}):c(n)}},8453(n,e,t){t.d(e,{R:()=>r,x:()=>o});var s=t(6540);const a={},i=s.createContext(a);function r(n){const e=s.useContext(i);return s.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function o(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(a):n.components||a:r(n.components),s.createElement(i.Provider,{value:e},n.children)}}}]);